data.query:
query segments($first: Int, $after: String, $sortKey: SegmentSortKeys, $reverse: Boolean, $query: String) {
    segments(first: $first, after: $after, sortKey: $sortKey, reverse: $reverse, query: $query) {
        edges {
            cursor
            node {
                id
                name
                creationDate
                lastEditDate
                query
            }
        }
        pageInfo {
            hasNextPage
        }
    }
}
